Infraestrutura como codigo para security - HealthTech Systems - cost-optimization:

**main.tf:**
```hcl
terraform {
  required_providers {
    oci = {
      source  = "oracle/oci"
      version = "~> 5.0"
    }
  }
}

provider "oci" {
  region = "ap-mumbai-1"
}

resource "oci_vault_secret" "main" {
  compartment_id = var.compartment_ocid
  display_name   = "security-networking-145"

  # configuração específica
  shape          = "VM.Standard.A1.Flex"

  tags = {
    project     = "HealthTech Systems - cost-optimization"
    environment = "networking"
    managed_by  = "terraform"
  }
}

variable "compartment_ocid" {
  type        = string
  description = "OCID do compartment networking"
}

output "resource_id" {
  value = oci_vault_secret.main.id
}
```

**variables.tf:**
```hcl
variable "compartment_ocid" {
  type        = string
  description = "OCID do compartment"
}

variable "region" {
  type        = string
  default     = "ap-mumbai-1"
  description = "Regiao OCI"
}
```

**Deploy:**
```bash
terraform init
terraform plan -var="compartment_ocid=<ocid>"
terraform apply -var="compartment_ocid=<ocid>" -auto-approve
```

**configuração:**
- Compartment: `networking`
- Region: `ap-mumbai-1`
- Shape: `VM.Standard.A1.Flex`
- OCPUs: `2`
- Storage: `100 GB`

